                           @bind="minPrice" @bind:event="oninput" min="0" step="0.01" />
                    <span>–</span>
                    <input type="number" class="form-control form-control-sm" placeholder="Max"
                           @bind="maxPrice" @bind:event="oninput" min="0" step="0.01" />
                </div>
            </div>

