                <button class="btn btn-primary btn-sm" @onclick="ApplyFiltersAsync">Apply Filters</button>
                <button class="btn btn-outline-secondary btn-sm" @onclick="ClearFiltersAsync">Clear Filters</button>
            </div>
        </div>

        <!-- Main Content -->
        <div class="catalog-main flex-grow-1">
            @if (isLoading)
            {
                <div class="d-flex justify-content-center align-items-center py-5">
                    <div class="spinner-border text-primary" role="status">
                        <span class="visually-hidden">Loading...</span>
                    </div>
                    <span class="ms-2">Loading products...</span>
                </div>
