+        if (page < 1 || page > totalPages) return;
+        currentPage = page;
+        await SearchAsync();
+    }
+
+    private async Task SearchAsync()
+    {
+        try
+        {
+            isLoading = true;
+            errorMessage = null;
+            await PerformSearchAsync();
+        }
+        catch (Exception ex)
+        {
+            errorMessage = ex.Message;
+        }
+        finally
+        {
+            isLoading = false;
+        }
+    }
